+    /// Apply profile defaults before other config sources
+    pub fn apply_defaults(&self) {
+        match self {
+            Profile::Dev => {
+                set_if_unset("RCH_LOG_LEVEL", "debug");
+                set_if_unset("RCH_LOG_FORMAT", "pretty");
+            }
+            Profile::Prod => {
